import graphene
from ariadne import QueryType, MutationType, make_executable_schema
from ariadne.constants import PLAYGROUND_HTML
from flask import Flask, request, jsonify
from flask_jwt_extended import JWTManager, jwt_required, create_access_token
from flask_sqlalchemy import SQLAlchemy

app = Flask(__name__)
app.config['SQLALCHEMY_DATABASE_URI'] = 'sqlite:///database.db'
db = SQLAlchemy(app)
jwt = JWTManager(app)

class User(db.Model):
    id = db.Column(db.Integer, primary_key=True)
    username = db.Column(db.String(80), unique=True, nullable=False)
    bio = db.Column(db.Text, nullable=False)
    email = db.Column(db.String(120), unique=True, nullable=False)
    phone = db.Column(db.String(20), nullable=False)
    address = db.Column(db.Text, nullable=False)

class Post(db.Model):
    id = db.Column(db.Integer, primary_key=True)
    title = db.Column(db.String(80), nullable=False)
    content = db.Column(db.Text, nullable=False)
    user_id = db.Column(db.Integer, db.ForeignKey('user.id'), nullable=False)

class UserType(graphene.ObjectType):
    username = graphene.String()
    bio = graphene.String()
    email = graphene.String()
    phone = graphene.String()
    address = graphene.String()

class PostType(graphene.ObjectType):
    title = graphene.String()
    content = graphene.String()

class Query(graphene.ObjectType):
    user = graphene.Field(UserType, id=graphene.ID())

    def resolve_user(self, info, id):
        user = User.query.get(id)
        return UserType(**user.__dict__)

class Mutation(graphene.ObjectType):
    login = graphene.Field(UserType, username=graphene.String(), password=graphene.String())
    register = graphene.Field(UserType, username=graphene.String(), email=graphene.String(), password=graphene.String())

    def resolve_login(self, info, username, password):
        user = User.query.filter_by(username=username).first()
        if user and user.password == password:
            access_token = create_access_token(identity=user.id)
            return UserType(**user.__dict__)
        return None

    def resolve_register(self, info, username, email, password):
        user = User(username=username, email=email, password=password)
        db.session.add(user)
        db.session.commit()
        return UserType(**user.__dict__)

class Middleware(graphene.ObjectType):
    current_user = graphene.Field(UserType)

schema = make_executable_schema(Query, Mutation, UserType, PostType, Middleware)

@app.route('/graphql', methods=['GET'])
def graphql_playground():
    return PLAYGROUND_HTML, 200

@app.route('/graphql', methods=['POST'])
def resolve_graphql():
    data = request.get_json()
    success, result = schema.execute(data['query'], context_value={'request': request})
    if success:
        return jsonify(graphene.json.dumps(result))
    else:
        return jsonify(graphene.json.dumps({'errors': [str(e) for e in result]}))

